changeSet.sql:
update results.results r set job_id = (
    select max(id)
    from schedule.schedule_check_units scu
    where (
        r.arrangement_id = scu.arrangement_id and
        r.check_unit_type = scu.check_unit_type and
        r.check_unit_value = scu.check_unit_value and
        r.content_id = cast(scu.erdi_id as bigint)
    )
);
